#include <iostream>
#include <string>
#include <algorithm>

class Player {
private:
    std::string name;
    int health;
    int maxHealth;
    int attack;
    int defense;
    int level;
    double experience;

public:
    Player(std::string n, int h, int a, int d) {
        setName(n);
        health = h;
        maxHealth = h;
        attack = a;
        defense = d;
        level = 1;
        experience = 0;
    }

    // --- Getters (read-only) ---
    std::string getName() const { return name; }
    int getHealth() const { return health; }
    int getMaxHealth() const { return maxHealth; }
    int getAttack() const { return attack; }
    int getDefense() const { return defense; }
    int getLevel() const { return level; }
    double getExperience() const { return experience; }

    // --- Setters (with validation) ---
    void setName(const std::string& newName) {
        if (newName.length() >= 2 && newName.length() <= 20) {
            name = newName;
        } else {
            std::cout << "Invalid name! Must be 2-20 characters." << std::endl;
            name = "Hero";
        }
    }

    void setHealth(int newHealth) {
        if (newHealth >= 0 && newHealth <= maxHealth) {
            health = newHealth;
        } else if (newHealth > maxHealth) {
            health = maxHealth;
        } else {
            health = 0;
        }
    }

    void setAttack(int newAttack) {
        if (newAttack >= 0) {
            attack = newAttack;
        } else {
            std::cout << "Attack cannot be negative!" << std::endl;
        }
    }

    void setDefense(int newDefense) {
        if (newDefense >= 0) {
            defense = newDefense;
        } else {
            std::cout << "Defense cannot be negative!" << std::endl;
        }
    }

    // --- Derived getters ---
    bool isAlive() const {
        return health > 0;
    }

    double getHealthPercent() const {
        return (static_cast<double>(health) / maxHealth) * 100.0;
    }

    void displayStats() const {
        std::cout << "\n=== Player Stats ===" << std::endl;
        std::cout << "Name: " << name << std::endl;
        std::cout << "Level: " << level << std::endl;
        std::cout << "Health: " << health << "/" << maxHealth 
                  << " (" << getHealthPercent() << "%)" << std::endl;
        std::cout << "Attack: " << attack << std::endl;
        std::cout << "Defense: " << defense << std::endl;
        std::cout << "Experience: " << experience << std::endl;
        std::cout << "Status: " << (isAlive() ? "Alive" : "Dead") << std::endl;
    }

    void takeDamage(int damage) {
        int actualDamage = damage - (defense / 2);
        if (actualDamage < 0) actualDamage = 0;
        setHealth(health - actualDamage);
        std::cout << name << " took " << actualDamage << " damage!" << std::endl;
    }

    void heal(int amount) {
        setHealth(health + amount);
        std::cout << name << " healed!" << std::endl;
    }
};

int main() {
    std::cout << "=== Getters & Setters ===" << std::endl;

    Player hero("Aragorn", 120, 25, 15);

    // Using getters (read)
    std::cout << "Name: " << hero.getName() << std::endl;
    std::cout << "Health: " << hero.getHealth() << std::endl;
    std::cout << "Attack: " << hero.getAttack() << std::endl;

    // Using setters (write with validation)
    hero.setAttack(30);
    std::cout << "After setting attack: " << hero.getAttack() << std::endl;

    // Invalid input handled
    hero.setName("A");  // Too short
    std::cout << "Name after invalid set: " << hero.getName() << std::endl;

    hero.setHealth(150);  // Above max
    std::cout << "Health after invalid set: " << hero.getHealth() << std::endl;

    hero.displayStats();

    hero.takeDamage(50);
    hero.displayStats();

    return 0;
}

