#include <iostream>
#include <string>

class Item {
private:
    std::string name;
    int value;
    int weight;
    std::string rarity;

public:
    Item(std::string n, int v, int w, std::string r) {
        setName(n);
        setValue(v);
        setWeight(w);
        setRarity(r);
    }

    // Getters
    std::string getName() const { return name; }
    int getValue() const { return value; }
    int getWeight() const { return weight; }
    std::string getRarity() const { return rarity; }

    // Setters with validation
    void setName(const std::string& newName) {
        if (!newName.empty()) {
            name = newName;
        } else {
            std::cout << "Invalid name! Must not be empty." << std::endl;
            name = "Unnamed";
        }
    }

    void setValue(int newValue) {
        if (newValue >= 0) {
            value = newValue;
        } else {
            std::cout << "Invalid value! Must be >= 0." << std::endl;
            value = 0;
        }
    }

    void setWeight(int newWeight) {
        if (newWeight >= 0) {
            weight = newWeight;
        } else {
            std::cout << "Invalid weight! Must be >= 0." << std::endl;
            weight = 0;
        }
    }

    void setRarity(const std::string& newRarity) {
        if (newRarity == "Common" || newRarity == "Rare" || 
            newRarity == "Epic" || newRarity == "Legendary") {
            rarity = newRarity;
        } else {
            std::cout << "Invalid rarity! Using 'Common'." << std::endl;
            rarity = "Common";
        }
    }

    void display() const {
        std::cout << "=== Item ===" << std::endl;
        std::cout << "Name: " << name << std::endl;
        std::cout << "Value: " << value << std::endl;
        std::cout << "Weight: " << weight << std::endl;
        std::cout << "Rarity: " << rarity << std::endl;
    }
};

int main() {
    Item sword("Iron Sword", 50, 3, "Common");
    sword.display();

    sword.setName("");
    sword.setValue(-10);
    sword.setRarity("Godly");

    sword.display();

    return 0;
}
